class Solution:
    def splitMessage(self, message, limit):
        L = len(message)
        for b in range(1, L + 1):
            bdigits = len(str(b))
            total_content = 0
            ok = True
            for a in range(1, b + 1):
                suffix = len(str(a)) + bdigits + 3
                content = limit - suffix
                if content <= 0:
                    ok = False
                    break
                total_content += content
            if not ok:
                continue
            if total_content >= L:
                res = []
                pos = 0
                for a in range(1, b + 1):
                    suffix = '<' + str(a) + '/' + str(b) + '>'
                    take = limit - len(suffix)
                    chunk = message[pos:pos + take]
                    res.append(chunk + suffix)
                    pos += len(chunk)
                    if pos >= L:
                        break
                if pos >= L:
                    return res
        return []

