var splitMessage = function(message, limit) {
    const n = message.length;
    let chosen = -1;
    for (let b = 1; b <= n; b++) {
        const bd = String(b).length;
        let cap = 0;
        let ok = true;
        for (let a = 1; a <= b; a++) {
            const suffix = String(a).length + bd + 3;
            const avail = limit - suffix;
            if (avail <= 0) { ok = false; break; }
            cap += avail;
        }
        if (!ok) continue;
        if (cap >= n) { chosen = b; break; }
    }
    if (chosen === -1) return [];
    const res = [];
    let pos = 0;
    for (let i = 1; i <= chosen; i++) {
        const suffix = '<' + i + '/' + chosen + '>';
        const take = limit - suffix.length;
        const chunk = message.slice(pos, pos + take);
        res.push(chunk + suffix);
        pos += chunk.length;
    }
    return res;
};
